function phase16BParseUrlMap(urlMap) {
  if (urlMap == null || urlMap === '') return {};
  if (typeof urlMap === 'object' && !Array.isArray(urlMap)) return urlMap;
  try {
    const parsed = JSON.parse(String(urlMap));
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) throw new Error('url-map must be a JSON object');
    return parsed;
  } catch (error) {
    throw new Error(`Invalid url-map JSON: ${error.message || String(error)}`);
  }
}

async function validateEbayPublicPictureUrlMiniBatchUrls({ urlMap = '{}' } = {}) {
  const parsedUrlMap = phase16BParseUrlMap(urlMap);
  const checklist = await buildEbayPublicPictureUrlMiniBatchImageIntakeChecklist({ limit: 5 });
  const readySet = new Set(PHASE16B_READY_LOW_RISK_ITEM_IDS);
  const blockedSet = new Set(PHASE16B_BLOCKED_HIGH_RISK_ITEM_IDS);
  const entries = Object.entries(parsedUrlMap);
  const validation_results = entries.map(([itemId, url]) => {
    const normalizedItemId = String(itemId || '').trim();
    const facts = phase15CUrlValidationFacts(url);
    const itemApproved = readySet.has(normalizedItemId);
    const itemBlocked = blockedSet.has(normalizedItemId);
    const allowedChanges = ['images'];
    const valid = itemApproved
      && !itemBlocked
      && facts.url_is_https === true
      && facts.url_host_is_not_localhost_or_private === true
      && facts.url_looks_like_image_url === true;
    return {
      item_id: normalizedItemId,
      picture_url: facts.picture_url,
      valid,
      item_id_in_approved_low_risk_mini_batch: itemApproved,
      item_id_blocked_high_risk: itemBlocked,
      url_is_https: facts.url_is_https,
      url_host_is_not_localhost_or_private: facts.url_host_is_not_localhost_or_private,
      url_looks_like_image_url: facts.url_looks_like_image_url,
      allowed_changes: allowedChanges,
      change_scope_remains_images_only: allowedChanges.length === 1 && allowedChanges[0] === 'images',
      ready_for_packet_creation: false,
      marketplace_write: false,
      url_host: facts.url_host,
      url_pathname: facts.url_pathname,
      url_parse_error: facts.url_parse_error,
      blockers: [
        ...(itemApproved ? [] : ['item_id_not_in_approved_low_risk_mini_batch']),
        ...(itemBlocked ? ['item_id_blocked_until_cached_evidence_refreshed'] : []),
        ...(facts.url_is_https ? [] : ['url_not_https']),
        ...(facts.url_host_is_not_localhost_or_private ? [] : ['url_host_localhost_or_private_or_invalid']),
        ...(facts.url_looks_like_image_url ? [] : ['url_does_not_look_like_image_url']),
      ],
    };
  });
  const missing_ready_item_ids = PHASE16B_READY_LOW_RISK_ITEM_IDS.filter(itemId => !Object.prototype.hasOwnProperty.call(parsedUrlMap, itemId));
  const invalid_item_ids = validation_results.filter(row => !row.valid).map(row => row.item_id);
  const validated_urls = Object.fromEntries(validation_results.map(row => [row.item_id, {
    valid: row.valid,
    picture_url: row.picture_url,
    url_is_https: row.url_is_https,
    url_host_is_not_localhost_or_private: row.url_host_is_not_localhost_or_private,
    url_looks_like_image_url: row.url_looks_like_image_url,
    item_id_in_approved_low_risk_mini_batch: row.item_id_in_approved_low_risk_mini_batch,
    allowed_changes: row.allowed_changes,
    change_scope_remains_images_only: row.change_scope_remains_images_only,
    blockers: row.blockers,
  }]));
  return {
    mini_batch_url_intake_ready: checklist.mini_batch_url_intake_ready,
    ready_item_ids: PHASE16B_READY_LOW_RISK_ITEM_IDS,
    blocked_item_ids: PHASE16B_BLOCKED_HIGH_RISK_ITEM_IDS,
    validated_urls,
    ready_for_packet_creation: false,
    marketplace_write: false,
    read_only: true,
    phase: '16B',
    operation: 'public_picture_url_mini_batch_validate_urls',
    supplied_item_ids: entries.map(([itemId]) => String(itemId || '').trim()),
    missing_ready_item_ids,
    invalid_item_ids,
    all_supplied_urls_valid: entries.length > 0 && invalid_item_ids.length === 0,
    validation_results,
    allowed_changes: ['images'],
    url_validation_rules: [
      'HTTPS only',
      'not localhost/private',
      'looks like image URL',
      'item_id is in the approved low-risk mini-batch list',
      'allowed_changes remains ["images"]',
    ],
    no_writes_performed: true,
    safety: phase16BMiniBatchImageIntakeSafety(),
    source: 'phase_16b_public_picture_url_mini_batch_validate_urls_v1',
  };
}

const PHASE16C_BLOCKED_CHANGES = ['title', 'item_specifics', 'price', 'inventory', 'quantity', 'description', 'category', 'shipping', 'payment', 'returns'];

function phase16CPacketPayload({ itemId, pictureUrl } = {}) {
  return {
    Item: {
      ItemID: String(itemId || ''),
      PictureDetails: {
        PictureURL: [String(pictureUrl || '')],
      },
    },
  };
}

function phase16CExplicitAbsences() {
  return {
    no_title: true,
    no_item_specifics: true,
    no_price: true,
    no_inventory: true,
    no_quantity: true,
    no_description: true,
    no_category: true,
    no_shipping: true,
    no_payment: true,
    no_returns: true,
  };
}

function phase16CSafety({ databaseWrite = false, requestCreated = false, packetCreated = false, eventCreated = false } = {}) {
  return {
    actual_ebay_call: false,
    actual_network_call: false,
    get_item_called: false,
    revise_fixed_price_item_called: false,
    upload_site_hosted_pictures_called: false,
    marketplace_write_performed: false,
    live_execution_performed: false,
    listing_changed: false,
    listing_revise_performed: false,
    execution_request_created: requestCreated,
    packet_created: packetCreated,
    audit_event_created: eventCreated,
    actual_database_write: databaseWrite,
    title_changes: false,
    item_specifics_changes: false,
    price_changes: false,
    inventory_changes: false,
    quantity_changes: false,
    description_changes: false,
    category_changes: false,
    shipping_changes: false,
    payment_changes: false,
    returns_changes: false,
    image_changes: packetCreated,
    ai_calls: false,
  };
}

async function phase16CExistingPacketRows({ itemId, pictureUrl, mutationHash } = {}) {
  try {
    const db = getClient();
    const { data: requests, error: requestError } = await db
      .from(REQUEST_TABLE)
      .select('*')
      .eq('metadata->>source', 'phase_16c_public_picture_url_mini_batch_packet')
      .eq('metadata->>item_id', String(itemId || ''))
      .eq('metadata->>public_picture_url', String(pictureUrl || ''))
      .eq('metadata->>public_picture_url_mutation_hash', String(mutationHash || ''))
      .order('id', { ascending: false })
      .limit(5);
    if (requestError) throw requestError;
    const requestIds = (requests || []).map(row => row.id).filter(id => id != null);
    let packets = [];
    if (requestIds.length) {
      const { data: packetRows, error: packetError } = await db
        .from(EBAY_LISTING_QUALITY_PACKET_TABLE)
        .select('*')
        .in('request_id', requestIds)
        .order('id', { ascending: false })
        .limit(20);
      if (packetError) throw packetError;
      packets = packetRows || [];
    }
    return { requests: requests || [], packets };
  } catch (e) {
    return { requests: [], packets: [], read_error: e.message || String(e) };
  }
}

async function buildEbayPublicPictureUrlMiniBatchPacketPreview({ urlMap = '{}' } = {}) {
  const validation = await validateEbayPublicPictureUrlMiniBatchUrls({ urlMap });
  const previews = [];
  for (const itemId of PHASE16B_READY_LOW_RISK_ITEM_IDS) {
    const row = validation.validated_urls?.[itemId] || null;
    const pictureUrl = row?.picture_url || null;
    const payloadPreview = phase16CPacketPayload({ itemId, pictureUrl });
    const plannedMutation = {
      images: {
        source_type: 'operator_supplied_public_https_url',
        PictureDetails: {
          PictureURL: pictureUrl ? [pictureUrl] : [],
        },
        public_picture_url: pictureUrl,
      },
    };
    const mutationHash = sha256Json({ item_id: itemId, payload: payloadPreview, planned_mutation: plannedMutation });
    const blockers = [];
    if (!row) blockers.push('url_not_supplied_for_ready_item');
    if (row?.valid !== true) blockers.push('phase_16b_url_validation_not_valid');
    if (row?.change_scope_remains_images_only !== true) blockers.push('change_scope_not_images_only');
    if (!pictureUrl) blockers.push('picture_url_missing');
    const existing = await phase16CExistingPacketRows({ itemId, pictureUrl, mutationHash });
    previews.push({
      item_id: itemId,
      operation: 'ReviseFixedPriceItem',
      change_scope: ['images'],
      picture_url: pictureUrl,
      marketplace_write: false,
      ready_for_packet_creation: blockers.length === 0,
      read_only: true,
      phase: '16C',
      validation: row,
      planned_mutation: plannedMutation,
      payload_preview: payloadPreview,
      payload_contains_only_item_id_and_picture_details: true,
      public_picture_url_mutation_hash: mutationHash,
      explicit_absences: phase16CExplicitAbsences(),
      blocked_changes: PHASE16C_BLOCKED_CHANGES,
      forbidden_fields_present: [],
      existing_request_id: existing.requests[0]?.id || null,
      existing_packet_id: existing.packets[0]?.id || null,
      blockers: [...new Set(blockers)],
      safety: phase16CSafety(),
      source: 'phase_16c_public_picture_url_mini_batch_packet_preview_item_v1',
    });
  }
  const ready = previews.length === PHASE16B_READY_LOW_RISK_ITEM_IDS.length
    && previews.every(row => row.ready_for_packet_creation === true)
    && validation.all_supplied_urls_valid === true
    && validation.missing_ready_item_ids.length === 0;
  return {
    read_only: true,
    phase: '16C',
    operation: 'public_picture_url_mini_batch_packet_preview',
    mini_batch_url_intake_ready: validation.mini_batch_url_intake_ready,
    ready_item_ids: PHASE16B_READY_LOW_RISK_ITEM_IDS,
    blocked_item_ids: PHASE16B_BLOCKED_HIGH_RISK_ITEM_IDS,
    preview_count: previews.length,
    previews,
    marketplace_write: false,
    ready_for_packet_creation: ready,
    live_execution_disabled: true,
    no_ebay_call_performed: true,
    blocked_changes: PHASE16C_BLOCKED_CHANGES,
    validation,
    safety: phase16CSafety(),
    source: 'phase_16c_public_picture_url_mini_batch_packet_preview_v1',
  };
}

