function phase16DParseRequestIds(requestIds) {
  const values = Array.isArray(requestIds) ? requestIds : String(requestIds || '').split(',');
  return [...new Set(values.map(value => intOrNull(value)).filter(value => value != null))];
}

function phase16DApprovalSafety() {
  return {
    read_only: true,
    actual_ebay_call: false,
    actual_network_call: false,
    get_item_called: false,
    revise_fixed_price_item_called: false,
    upload_site_hosted_pictures_called: false,
    marketplace_write_performed: false,
    live_execution_performed: false,
    listing_changed: false,
    packet_mutation_performed: false,
    execution_request_created: false,
    packet_created: false,
    actual_database_write: false,
    title_changes: false,
    item_specifics_changes: false,
    price_changes: false,
    inventory_changes: false,
    quantity_changes: false,
    description_changes: false,
    category_changes: false,
    shipping_changes: false,
    payment_changes: false,
    returns_changes: false,
    image_changes: false,
    ai_calls: false,
  };
}

function phase16DExactApprovalText(entries = []) {
  const requestIds = entries.map(row => row.request_id).join(',');
  const packetIds = entries.map(row => row.packet_id).join(',');
  const itemIds = entries.map(row => row.item_id).join(',');
  const pictureLines = entries.map(row => `PictureDetails.PictureURL for item_id=${row.item_id}: ${row.picture_url} only.`);
  return [
    'Actual eBay mini-batch listing revise approval for images-only public PictureURL packets.',
    `request_id=${requestIds} only.`,
    `packet_id=${packetIds} only.`,
    `item_id=${itemIds} only.`,
    `Batch size: ${entries.length}.`,
    'Allowed operation: ReviseFixedPriceItem only.',
    'Allowed changes: images only.',
    ...pictureLines,
    'No title changes.',
    'No item_specifics changes.',
    'No price, inventory, or quantity changes.',
    'No description, category, shipping, payment, or returns changes.',
    'Forbidden operation: UploadSiteHostedPictures.',
    'One live ReviseFixedPriceItem attempt per request only.',
    'Stop and report if any item fails; do not retry failed item automatically.',
    'Record every eBay response.',
    'Do not push.',
  ].join('\n');
}

async function buildEbayPublicPictureUrlMiniBatchFinalApprovalChecklist({ requestIds } = {}) {
  const ids = phase16DParseRequestIds(requestIds);
  if (ids.length === 0) throw new Error('request-ids is required');
  const db = getClient();
  const { data: requests, error: requestError } = await db
    .from(REQUEST_TABLE)
    .select('*')
    .in('id', ids)
    .order('id', { ascending: true });
  if (requestError) throw requestError;
  const { data: packets, error: packetError } = await db
    .from(EBAY_LISTING_QUALITY_PACKET_TABLE)
    .select('*')
    .in('request_id', ids)
    .order('id', { ascending: true });
  if (packetError) throw packetError;
  const requestById = new Map((requests || []).map(row => [row.id, row]));
  const packetByRequestId = new Map((packets || []).map(row => [row.request_id, row]));
  const expectedRequestIds = [8, 9, 10];
  const expectedPacketIds = [8, 9, 10];
  const expectedItemIds = ['206332929888', '206371786121', '206387679082'];
  const entries = ids.map(id => {
    const request = requestById.get(id) || null;
    const packet = packetByRequestId.get(id) || null;
    const plannedMutation = packet?.planned_mutation || request?.requested_action?.planned_mutation || {};
    const pictureUrls = Array.isArray(plannedMutation?.images?.PictureDetails?.PictureURL)
      ? plannedMutation.images.PictureDetails.PictureURL
      : (plannedMutation?.images?.PictureDetails?.PictureURL ? [plannedMutation.images.PictureDetails.PictureURL] : []);
    const itemId = String(packet?.item_id || request?.metadata?.item_id || request?.requested_action?.target_item_id || '');
    const pictureUrl = pictureUrls[0] || request?.metadata?.public_picture_url || request?.requested_action?.public_picture_url || null;
    const payloadPreview = request?.requested_action?.payload_preview || request?.dry_run_result?.payload_preview || phase16CPacketPayload({ itemId, pictureUrl });
    const forbiddenFieldsPresent = PHASE16C_BLOCKED_CHANGES.filter(field => {
      if (field === 'item_specifics') return Boolean(payloadPreview?.Item?.ItemSpecifics);
      if (field === 'price') return Boolean(payloadPreview?.Item?.StartPrice || payloadPreview?.Item?.Price);
      if (field === 'inventory' || field === 'quantity') return Boolean(payloadPreview?.Item?.Quantity || payloadPreview?.InventoryStatus);
      return Boolean(payloadPreview?.Item?.[field] || payloadPreview?.Item?.[field.charAt(0).toUpperCase() + field.slice(1)]);
    });
    const blockers = [];
    if (!request) blockers.push('request_not_found');
    if (!packet) blockers.push('packet_not_found');
    if (!expectedRequestIds.includes(id)) blockers.push('request_id_not_in_phase_16c_batch');
    if (!expectedPacketIds.includes(packet?.id)) blockers.push('packet_id_not_in_phase_16c_batch');
    if (!expectedItemIds.includes(itemId)) blockers.push('item_id_not_in_phase_16c_batch');
    if (request?.status !== 'pending_approval') blockers.push('request_not_pending_approval');
    if (packet?.status !== 'packet_recorded') blockers.push('packet_not_recorded');
    if (request?.executed_at != null || request?.execution_result != null) blockers.push('request_already_executed');
    if (request?.metadata?.source !== 'phase_16c_public_picture_url_mini_batch_packet') blockers.push('request_not_phase_16c_source');
    if (request?.metadata?.live_execution_disabled !== true) blockers.push('live_execution_not_disabled');
    if (request?.metadata?.approval_gated !== true) blockers.push('request_not_approval_gated');
    if ((request?.requested_action?.planned_mutation_fields || []).join(',') !== 'images') blockers.push('planned_mutation_fields_not_images_only');
    if (pictureUrls.length !== 1 || !pictureUrl) blockers.push('picture_url_not_exactly_one');
    if (forbiddenFieldsPresent.length > 0) blockers.push('forbidden_fields_present');
    const ready = blockers.length === 0;
    return {
      request_id: id,
      packet_id: packet?.id || null,
      item_id: itemId || null,
      operation: 'ReviseFixedPriceItem',
      change_scope: ['images'],
      picture_url: pictureUrl,
      blocked_changes: PHASE16C_BLOCKED_CHANGES,
      ready_for_operator_approval: ready,
      live_execution_performed: false,
      marketplace_write: false,
      request_status: request?.status || null,
      packet_status: packet?.status || null,
      confirmation_status: packet?.confirmation_status || 'not_confirmed',
      final_approval_status: request?.final_approval_status || 'not_requested',
      payload_preview: payloadPreview,
      explicit_absences: phase16CExplicitAbsences(),
      forbidden_fields_present: forbiddenFieldsPresent,
      packet_payload_is_images_only: forbiddenFieldsPresent.length === 0 && pictureUrls.length === 1,
      no_packet_mutation_performed: true,
      blockers,
    };
  });
  const readyForOperatorApproval = entries.length === expectedRequestIds.length
    && entries.every(row => row.ready_for_operator_approval === true)
    && expectedRequestIds.every(id => ids.includes(id));
  return {
    read_only: true,
    phase: '16D',
    operation: 'public_picture_url_mini_batch_final_approval_checklist',
    request_ids: ids,
    expected_request_ids: expectedRequestIds,
    expected_packet_ids: expectedPacketIds,
    expected_item_ids: expectedItemIds,
    batch_size: entries.length,
    checklists: entries,
    ready_for_operator_approval: readyForOperatorApproval,
    exact_operator_approval_text: phase16DExactApprovalText(entries),
    live_execution_performed: false,
    marketplace_write: false,
    no_packet_mutation_performed: true,
    no_writes_performed: true,
    safety: phase16DApprovalSafety(),
    source: 'phase_16d_public_picture_url_mini_batch_final_approval_checklist_v1',
  };
}

async function phase16ELiveAttemptCount({ requestId }) {
  const db = getClient();
  const liveTypes = [
    'phase_16e_public_picture_url_mini_batch_revise_started',
    'phase_16e_public_picture_url_mini_batch_revise_completed',
    'phase_16e_public_picture_url_mini_batch_revise_failed',
    'marketplace_execution_started',
    'marketplace_execution_completed',
    'marketplace_execution_failed',
    'request_executed',
    'execution_completed',
    'execution_failed',
  ];
  const { count, error } = await db
    .from(EVENT_TABLE)
    .select('*', { count: 'exact', head: true })
    .eq('request_id', requestId)
    .in('event_type', liveTypes);
  if (error) throw error;
  return count || 0;
}

function phase16ENormalizeApprovalText(text) {
  return String(text || '').replace(/\r\n/g, '\n').replace(/\s+/g, ' ').trim();
}

async function executeEbayPublicPictureUrlMiniBatchApprovedLiveRevise({ requestIds, approvalText, dryRun = true, write = false, liveEnabled = false } = {}) {
  const ids = phase16DParseRequestIds(requestIds);
  if (ids.length === 0) throw new Error('request-ids is required');
  const approvalChecklist = await buildEbayPublicPictureUrlMiniBatchFinalApprovalChecklist({ requestIds: ids });
  const exactApprovalText = approvalChecklist.exact_operator_approval_text;
  const approvalTextMatches = phase16ENormalizeApprovalText(approvalText) === phase16ENormalizeApprovalText(exactApprovalText);
  const isDryRun = dryRun !== false || write !== true;
  const envLiveEnabled = String(process.env.HERMES_EBAY_LIVE_EXECUTION_ENABLED || '').toLowerCase() === 'true';
  const expectedRequestIds = [8, 9, 10];
  const previousLiveAttemptCounts = {};
  for (const id of ids) previousLiveAttemptCounts[id] = await phase16ELiveAttemptCount({ requestId: id });
  const blockers = [];
  if (JSON.stringify(ids) !== JSON.stringify(expectedRequestIds)) blockers.push('request_ids_must_be_8_9_10_in_order');
  if (approvalChecklist.ready_for_operator_approval !== true) blockers.push('phase_16d_readiness_not_met');
  if (!approvalTextMatches) blockers.push('exact_operator_approval_text_missing_or_mismatch');
  for (const [id, count] of Object.entries(previousLiveAttemptCounts)) {
    if (count > 0) blockers.push(`previous_live_attempt_exists_for_request_${id}`);
  }
  if (!isDryRun && liveEnabled !== true) blockers.push('live_execution_flag_not_enabled');
  if (!isDryRun && envLiveEnabled !== true) blockers.push('live_execution_env_not_enabled');
  const base = {
    phase: '16E',
    operation: 'public_picture_url_mini_batch_approved_live_revise',
    request_ids: ids,
    packet_ids: approvalChecklist.checklists.map(row => row.packet_id),
    item_ids: approvalChecklist.checklists.map(row => row.item_id),
    batch_size: approvalChecklist.batch_size,
    dry_run: isDryRun,
    write_requested: write === true,
    live_enabled: liveEnabled === true,
    env_live_enabled: envLiveEnabled,
    approval_text_matches: approvalTextMatches,
    previous_live_attempt_counts: previousLiveAttemptCounts,
    one_live_revise_fixed_price_item_attempt_per_request_only: true,
    stop_on_first_failure: true,
    no_automatic_retry: true,
    approval_checklist: approvalChecklist,
    blockers: [...new Set(blockers)],
    actual_ebay_call: false,
    upload_site_hosted_pictures_called: false,
    revise_fixed_price_item_called: false,
    marketplace_write_performed: false,
    ai_calls: false,
    source: 'phase_16e_public_picture_url_mini_batch_approved_live_revise_v1',
  };
  if (isDryRun || blockers.length) {
    return {
      ...base,
      blocked: blockers.length > 0,
      would_call_ebay: blockers.length === 0,
      results: approvalChecklist.checklists.map(row => ({
        request_id: row.request_id,
        packet_id: row.packet_id,
        item_id: row.item_id,
        picture_url: row.picture_url,
        would_attempt_live_revise: blockers.length === 0,
        request_body_xml_preview: buildPhase14AVPublicPictureUrlReviseRequestBody({ images: { PictureDetails: { PictureURL: [row.picture_url] } } }, row.item_id),
      })),
      safety: {
        actual_ebay_call: false,
        actual_network_call: false,
        get_item_called: false,
        upload_site_hosted_pictures_called: false,
        revise_fixed_price_item_called: false,
        marketplace_write_performed: false,
        listing_changed: false,
        actual_database_write: false,
        ai_calls: false,
      },
    };
  }

  const results = [];
  let stoppedAfterFailure = false;
  for (const entry of approvalChecklist.checklists) {
    const plannedMutation = { images: { PictureDetails: { PictureURL: [entry.picture_url] } } };
    const requestBody = buildPhase14AVPublicPictureUrlReviseRequestBody(plannedMutation, entry.item_id);
    const startedEvent = await recordExecutionEvent({
      requestId: entry.request_id,
      eventType: 'phase_16e_public_picture_url_mini_batch_revise_started',
      actor: 'operator',
      payload: {
        phase: '16E',
        request_id: entry.request_id,
        packet_id: entry.packet_id,
        item_id: entry.item_id,
        api_operation: 'ReviseFixedPriceItem',
        allowed_changes: ['images'],
        forbidden_operation: 'UploadSiteHostedPictures',
        forbidden_changes: PHASE16C_BLOCKED_CHANGES,
        picture_details_picture_url: entry.picture_url,
        one_live_revise_fixed_price_item_attempt_only: true,
        approval_text_hash: sha256Text(approvalText),
        actual_ebay_call_starting: true,
      },
    });
    let rawResponse;
    let parsedResponse;
    let thrownError = null;
    try {
      const ebay = new EbayAPI();
      rawResponse = await ebay.callTradingAPI('ReviseFixedPriceItem', requestBody);
      parsedResponse = parseEbayReviseFixedPriceItemResponse(rawResponse);
    } catch (e) {
      thrownError = e;
      parsedResponse = {
        success: false,
        ack: 'Exception',
        item_id: entry.item_id,
        correlation_id: null,
        timestamp: new Date().toISOString(),
        warnings: [],
        errors: [{ message: e.message || String(e) }],
      };
    }
    const sanitized = sanitizePhase14AVEbayResponse(parsedResponse);
    const status = sanitized.success ? 'executed' : 'failed';
    const completionEventType = sanitized.success
      ? 'phase_16e_public_picture_url_mini_batch_revise_completed'
      : 'phase_16e_public_picture_url_mini_batch_revise_failed';
    const executionResult = {
      phase: '16E',
      request_id: entry.request_id,
      packet_id: entry.packet_id,
      item_id: entry.item_id,
      marketplace: 'ebay',
      api_operation: 'ReviseFixedPriceItem',
      operation: 'images_only_public_picture_url_update',
      actual_ebay_call: true,
      actual_network_call: true,
      upload_site_hosted_pictures_called: false,
      revise_fixed_price_item_called: true,
      marketplace_write_performed: true,
      listing_changed: sanitized.success,
      title_changes: false,
      item_specifics_changes: false,
      price_changes: false,
      inventory_changes: false,
      quantity_changes: false,
      description_changes: false,
      category_changes: false,
      shipping_changes: false,
      payment_changes: false,
      returns_changes: false,
      allowed_changes: ['images'],
      picture_details_picture_url: entry.picture_url,
      ebay_response: sanitized,
      error: thrownError ? { message: thrownError.message || String(thrownError) } : null,
      recorded_at: new Date().toISOString(),
    };
    const request = await getExecutionRequest({ requestId: entry.request_id });
    const db = getClient();
    const { data: updatedRequest, error: updateError } = await db
      .from(REQUEST_TABLE)
      .update({
        status,
        executed_at: new Date().toISOString(),
        execution_result: executionResult,
        final_approval_status: 'approved',
        final_approval_actor: 'operator',
        final_approved_at: new Date().toISOString(),
        final_approval_policy_version: 'phase_16d_public_picture_url_mini_batch_final_approval_v1',
        final_approval_dry_run_hash: sha256Json({ request_ids: ids, packet_ids: approvalChecklist.checklists.map(row => row.packet_id), exact_approval_text: exactApprovalText }),
        final_approval_snapshot: {
          exact_approval_text: exactApprovalText,
          supplied_approval_text_hash: sha256Text(approvalText),
          readiness: approvalChecklist,
        },
        metadata: {
          ...(request.metadata || {}),
          phase_16e_live_attempted: true,
          marketplace_write_performed: true,
          revise_fixed_price_item_called: true,
          upload_site_hosted_pictures_called: false,
          listing_changed: sanitized.success,
          phase_16e_status: status,
          phase_16e_ebay_ack: sanitized.ack,
        },
      })
      .eq('id', entry.request_id)
      .select('*')
      .single();
    if (updateError) throw updateError;
    const completionEvent = await recordExecutionEvent({
      requestId: entry.request_id,
      eventType: completionEventType,
      actor: 'operator',
      payload: executionResult,
    });
    results.push({
      request_id: entry.request_id,
      packet_id: entry.packet_id,
      item_id: entry.item_id,
      picture_url: entry.picture_url,
      started_event_id: startedEvent?.id || null,
      completion_event_id: completionEvent?.id || null,
      updated_request_status: updatedRequest.status,
      success: sanitized.success,
      ebay_response: sanitized,
      execution_result: executionResult,
    });
    if (!sanitized.success) {
      stoppedAfterFailure = true;
      break;
    }
  }
  return {
    ...base,
    dry_run: false,
    blocked: false,
    results,
    attempted_count: results.length,
    success_count: results.filter(row => row.success === true).length,
    failure_count: results.filter(row => row.success !== true).length,
    stopped_after_failure: stoppedAfterFailure,
    skipped_after_failure_request_ids: stoppedAfterFailure ? ids.slice(results.length) : [],
    actual_ebay_call: results.length > 0,
    actual_network_call: results.length > 0,
    upload_site_hosted_pictures_called: false,
    revise_fixed_price_item_called: results.length > 0,
    marketplace_write_performed: results.length > 0,
    listing_changed: results.some(row => row.success === true),
    safety: {
      actual_ebay_call: results.length > 0,
      actual_network_call: results.length > 0,
      get_item_called: false,
      upload_site_hosted_pictures_called: false,
      revise_fixed_price_item_called: results.length > 0,
      marketplace_write_performed: results.length > 0,
      listing_changed: results.some(row => row.success === true),
      title_changes: false,
      item_specifics_changes: false,
      price_changes: false,
      inventory_changes: false,
      quantity_changes: false,
      actual_database_write: true,
      ai_calls: false,
    },
  };
}

function phase16FListingImageEvidenceSummary(evidence, expected = {}) {
  if (!evidence || !['Success', 'Warning'].includes(String(evidence.ack || ''))) {
    return {
      get_item_readable: false,
      listing_image_appears_updated: false,
      item_id_matches: false,
      picture_present: false,
      requested_picture_url_retained: false,
      picture_url_transformed_to_ebay_hosted: false,
    };
  }
  const pictureUrls = evidence.picture_urls || [];
  const requestedPictureUrl = expected.picture_url || null;
  const requestedPictureUrlRetained = Boolean(requestedPictureUrl) && pictureUrls.includes(requestedPictureUrl);
  const pictureUrlTransformedToEbayHosted = pictureUrls.some(url => /^https:\/\/i\.ebayimg\.com\//i.test(String(url || '')));
  const picturePresent = requestedPictureUrlRetained || pictureUrlTransformedToEbayHosted || pictureUrls.length > 0;
  const itemIdMatches = String(evidence.item_id || '') === String(expected.item_id || '');
  return {
    get_item_readable: true,
    listing_image_appears_updated: itemIdMatches && picturePresent,
    item_id_matches: itemIdMatches,
    picture_present: picturePresent,
    requested_picture_url_retained: requestedPictureUrlRetained,
    picture_url_transformed_to_ebay_hosted: pictureUrlTransformedToEbayHosted,
  };
}

async function phase16FLoadRequestPacketEvents({ requestId, packetId }) {
  const request = await getExecutionRequest({ requestId });
  const packet = await getEbayListingQualityPacket({ packetId });
  const db = getClient();
  const { data: events, error } = await db
    .from(EVENT_TABLE)
    .select('id, event_type, actor, payload, created_at')
    .eq('request_id', requestId)
    .order('id', { ascending: true });
  if (error) throw error;
  return { request, packet, events: events || [] };
}

async function buildEbayPublicPictureUrlMiniBatchPostLiveAudit({ requestIds } = {}) {
  const ids = phase16DParseRequestIds(requestIds);
  if (ids.length === 0) throw new Error('request-ids is required');
  const expectedRows = [
    { request_id: 8, packet_id: 8, item_id: '206332929888', picture_url: 'https://pub-cac9dbf5e5f04a9c83d2788169df18e5.r2.dev/206332929888.jpg', started_event_id: 23, completion_event_id: 24 },
    { request_id: 9, packet_id: 9, item_id: '206371786121', picture_url: 'https://pub-cac9dbf5e5f04a9c83d2788169df18e5.r2.dev/206371786121.jpg', started_event_id: 25, completion_event_id: 26 },
    { request_id: 10, packet_id: 10, item_id: '206387679082', picture_url: 'https://pub-cac9dbf5e5f04a9c83d2788169df18e5.r2.dev/206387679082.jpg', started_event_id: 27, completion_event_id: 28 },
  ];
  const expectedRequestIds = expectedRows.map(row => row.request_id);
  const duplicateGuard = {
    excluded_request_ids: expectedRequestIds,
    excluded_packet_ids: expectedRows.map(row => row.packet_id),
    excluded_item_ids: expectedRows.map(row => row.item_id),
    request_ids_8_9_10_excluded: true,
    packet_ids_8_9_10_excluded: true,
    item_ids_206332929888_206371786121_206387679082_excluded: true,
  };
  const results = [];
  for (const expected of expectedRows.filter(row => ids.includes(row.request_id))) {
    const { request, packet, events } = await phase16FLoadRequestPacketEvents({ requestId: expected.request_id, packetId: expected.packet_id });
    const startedEvent = events.find(event => event.id === expected.started_event_id)
      || events.find(event => event.event_type === 'phase_16e_public_picture_url_mini_batch_revise_started');
    const completionEvent = events.find(event => event.id === expected.completion_event_id)
      || events.find(event => /^phase_16e_public_picture_url_mini_batch_revise_(completed|failed)$/.test(String(event.event_type || '')));
    let getItemEvidence = null;
    let getItemError = null;
    try {
      const ebay = new EbayAPI();
      const raw = await ebay.callTradingAPI('GetItem', `<ItemID>${phase14AVXmlEscape(expected.item_id)}</ItemID><DetailLevel>ReturnAll</DetailLevel><IncludeItemSpecifics>true</IncludeItemSpecifics>`);
      getItemEvidence = phase14AVParseGetItemEvidence(raw);
    } catch (e) {
      getItemError = e.message || String(e);
    }
    const executionResult = request?.execution_result || null;
    const ebayAck = executionResult?.ebay_response?.ack || null;
    const ackAccepted = ['Warning', 'Success'].includes(String(ebayAck || ''));
    const packetTerminal = ['packet_recorded', 'executed', 'closed', 'confirmed'].includes(String(packet?.status || ''));
    const listingImageEvidence = phase16FListingImageEvidenceSummary(getItemEvidence, expected);
    const listingImageAppearsUpdated = listingImageEvidence.get_item_readable
      ? listingImageEvidence.listing_image_appears_updated
      : executionResult?.listing_changed === true;
    const forbiddenChangeAudit = {
      no_title_changes: executionResult?.title_changes === false,
      no_item_specifics_changes: executionResult?.item_specifics_changes === false,
      no_price_changes: executionResult?.price_changes === false,
      no_inventory_changes: executionResult?.inventory_changes === false,
      no_quantity_changes: executionResult?.quantity_changes === false,
      no_description_changes: executionResult?.description_changes === false,
      no_category_changes: executionResult?.category_changes === false,
      no_shipping_changes: executionResult?.shipping_changes === false,
      no_payment_changes: executionResult?.payment_changes === false,
      no_returns_changes: executionResult?.returns_changes === false,
    };
    const forbiddenChangeAuditClean = Object.values(forbiddenChangeAudit).every(Boolean);
    const requestExecuted = request?.status === 'executed' && request?.executed_at != null && executionResult != null;
    const success = requestExecuted
      && packetTerminal
      && Boolean(startedEvent)
      && Boolean(completionEvent)
      && ackAccepted
      && listingImageAppearsUpdated
      && forbiddenChangeAuditClean;
    results.push({
      request_id: expected.request_id,
      packet_id: expected.packet_id,
      item_id: expected.item_id,
      picture_url: expected.picture_url,
      success,
      request_status: request?.status || null,
      packet_status: packet?.status || null,
      packet_status_terminal_or_equivalent: packetTerminal,
      started_event_id: startedEvent?.id || null,
      started_event_exists: Boolean(startedEvent),
      completion_event_id: completionEvent?.id || null,
      completion_event_exists: Boolean(completionEvent),
      execution_result_recorded: executionResult != null,
      ebay_response_ack: ebayAck,
      ebay_response_ack_success_or_warning: ackAccepted,
      listing_image_appears_updated: listingImageAppearsUpdated,
      listing_image_evidence: listingImageEvidence,
      get_item_evidence: getItemEvidence,
      get_item_error: getItemError,
      get_item_read_only_call_performed: getItemEvidence != null,
      no_additional_live_revise_attempt_needed: success,
      no_additional_live_revise_attempt_allowed: true,
      record_only_reconciliation_needed: !requestExecuted || !executionResult,
      reconciliation_already_complete: requestExecuted && Boolean(startedEvent) && Boolean(completionEvent) && ackAccepted && forbiddenChangeAuditClean,
      forbidden_change_audit: forbiddenChangeAudit,
      execution_result: executionResult,
      events: events.map(event => ({ id: event.id, event_type: event.event_type, actor: event.actor, created_at: event.created_at })),
    });
  }
  const successCount = results.filter(row => row.success === true).length;
  const failureCount = results.length - successCount;
  const reconciliationComplete = results.length === expectedRows.length
    && results.every(row => row.reconciliation_already_complete === true && row.record_only_reconciliation_needed === false);
  const phase16Complete = JSON.stringify(ids) === JSON.stringify(expectedRequestIds)
    && successCount === expectedRows.length
    && failureCount === 0
    && reconciliationComplete === true;
  const exactRecordOnlyReconciliationApprovalText = [
    'Record-only Hermes reconciliation approval for Phase 16E already-executed mini-batch public PictureURL live revise.',
    'request_id=8,9,10 only.',
    'packet_id=8,9,10 only.',
    'item_id=206332929888,206371786121,206387679082 only.',
    'No eBay calls.',
    'Do not call GetItem.',
    'Do not call ReviseFixedPriceItem.',
    'Do not call UploadSiteHostedPictures.',
    'No marketplace writes.',
    'Allowed internal DB writes only: mark any unreconciled request_id among 8,9,10 executed, attach existing execution_result from Phase 16F audit, create completion event.',
    'Forbidden changes: listing fields, price, inventory, quantity, description, category, shipping, payment, returns.',
    'One record-only reconciliation attempt only.',
    'Do not push.',
  ].join('\n');
  return {
    read_only: true,
    phase: '16F',
    operation: 'public_picture_url_mini_batch_post_live_audit',
    phase_16_complete: phase16Complete,
    audited_request_ids: ids,
    expected_request_ids: expectedRequestIds,
    success_count: successCount,
    failure_count: failureCount,
    reconciliation_complete: reconciliationComplete,
    duplicate_guard_active: true,
    no_further_live_action_required: phase16Complete,
    no_further_live_action_allowed: true,
    record_only_reconciliation_needed: results.some(row => row.record_only_reconciliation_needed === true),
    record_only_reconciliation_noop: results.every(row => row.record_only_reconciliation_needed !== true),
    exact_record_only_reconciliation_approval_text: results.some(row => row.record_only_reconciliation_needed === true)
      ? exactRecordOnlyReconciliationApprovalText
      : null,
    duplicate_guard: duplicateGuard,
    results,
    safety: {
      actual_ebay_call: results.some(row => row.get_item_read_only_call_performed === true),
      actual_network_call: results.some(row => row.get_item_read_only_call_performed === true),
      get_item_read_only_call_performed: results.some(row => row.get_item_read_only_call_performed === true),
      revise_fixed_price_item_called: false,
      upload_site_hosted_pictures_called: false,
      marketplace_write_performed: false,
      live_execution_performed: false,
      listing_changed_by_audit: false,
      title_changes: false,
      item_specifics_changes: false,
      price_changes: false,
      inventory_changes: false,
      quantity_changes: false,
      description_changes: false,
      category_changes: false,
      shipping_changes: false,
      payment_changes: false,
      returns_changes: false,
      actual_database_write: false,
      ai_calls: false,
    },
    source: 'phase_16f_public_picture_url_mini_batch_post_live_audit_v1',
  };
}

function phase17AToNumber(value, fallback = null) {
  const n = Number.parseFloat(value);
  return Number.isFinite(n) ? n : fallback;
}

function phase17AToInteger(value, fallback = 0) {
  const n = Number.parseInt(value, 10);
  return Number.isFinite(n) ? n : fallback;
}

function phase17ARoundMoney(value) {
  const n = phase17AToNumber(value, 0) || 0;
  return Math.round(n * 100) / 100;
}

function phase17ASignalPriority(type) {
  const priority = {
    dead_stock: 100,
    no_recent_sales: 85,
    stock_risk: 80,
    missing_cost: 75,
    competitor_lower_price: 70,
    price_attack: 95,
    low_margin_risk: 90,
    overstock: 82,
    slow_mover: 78,
  };
  return priority[type] || 10;
}

function phase17AOpportunityType(signals) {
  const types = (signals || []).map(signal => signal.type);
  const order = ['price_attack', 'low_margin_risk', 'dead_stock', 'overstock', 'no_recent_sales', 'slow_mover', 'stock_risk', 'missing_cost', 'competitor_lower_price'];
  return order.find(type => types.includes(type)) || types[0] || 'hold';
}

function phase17AEstimatedImpact({ opportunityType, availableQuantity, currentPrice, recentSales, marginPct }) {
  const inventoryValue = Math.max(0, availableQuantity) * Math.max(0, currentPrice);
  if (['price_attack', 'low_margin_risk'].includes(opportunityType)) return 'high';
  if (opportunityType === 'dead_stock' && inventoryValue >= 300) return 'high';
  if (opportunityType === 'overstock' && inventoryValue >= 500) return 'high';
  if (opportunityType === 'missing_cost' && currentPrice > 0) return 'medium';
  if (opportunityType === 'stock_risk' && recentSales > 0) return 'medium';
  if (marginPct != null && marginPct < 10) return 'medium';
  return inventoryValue >= 100 ? 'medium' : 'low';
}

function phase17ANextAction(opportunityType) {
  const map = {
    dead_stock: 'review_inventory',
    no_recent_sales: 'review_inventory',
    stock_risk: 'review_inventory',
    missing_cost: 'review_cost',
    competitor_lower_price: 'review_price',
    price_attack: 'review_price',
    low_margin_risk: 'review_price',
    overstock: 'review_inventory',
    slow_mover: 'review_inventory',
  };
  return map[opportunityType] || 'hold';
}

function phase17AAdditionalSignals(context, sourceRow = {}) {
  const signals = [];
  const detectedAt = new Date().toISOString();
  const price = phase17AToNumber(context?.pricing?.current_price || context?.platforms?.ebay?.price, 0) || 0;
  const cost = phase17AToNumber(sourceRow.cost_usd ?? sourceRow.cost ?? sourceRow.unit_cost ?? sourceRow.purchase_cost ?? context?.pricing?.cost, null);
  const available = phase17AToInteger(context?.inventory?.total_available ?? sourceRow.ebay_api_stock ?? sourceRow.stock, 0);
  const recentSales = phase17AToInteger(context?.sales?.units_30d ?? sourceRow.sales_count_30d ?? 0, 0);
  const totalSales = phase17AToInteger(sourceRow.sales_count ?? sourceRow.sold_quantity ?? context?.platforms?.ebay?.sold_quantity, 0);
  if (cost != null && cost > 0 && price > 0) {
    const marginPct = ((price - cost) / price) * 100;
    if (marginPct < 10) {
      signals.push({
        type: 'low_margin_risk',
        severity: marginPct < 0 ? 'critical' : 'warning',
        value: {
          current_price: phase17ARoundMoney(price),
          cost: phase17ARoundMoney(cost),
          estimated_margin_pct: Math.round(marginPct * 100) / 100,
        },
        detected_at: detectedAt,
      });
    }
  }
  if (available >= 10 && recentSales === 0) {
    signals.push({
      type: 'overstock',
      severity: available >= 30 ? 'warning' : 'info',
      value: { available_quantity: available, recent_sales: recentSales, window_days: 30 },
      detected_at: detectedAt,
    });
  } else if (available > 0 && totalSales <= 1 && recentSales === 0) {
    signals.push({
      type: 'slow_mover',
      severity: 'info',
      value: { available_quantity: available, recent_sales: recentSales, total_sales: totalSales, window_days: 30 },
      detected_at: detectedAt,
    });
  }
  return signals;
}

function phase17AOpportunityFromContext(context, sourceRow = {}) {
  const currentPrice = phase17AToNumber(context?.pricing?.current_price || context?.platforms?.ebay?.price, 0) || 0;
  const cost = phase17AToNumber(sourceRow.cost_usd ?? sourceRow.cost ?? sourceRow.unit_cost ?? sourceRow.purchase_cost ?? context?.pricing?.cost, null);
  const availableQuantity = phase17AToInteger(context?.inventory?.total_available ?? sourceRow.ebay_api_stock ?? sourceRow.stock, 0);
  const recentSales = phase17AToInteger(context?.sales?.units_30d ?? 0, 0);
  const signals = [...(context?.signals || []), ...phase17AAdditionalSignals(context, sourceRow)];
  const actionableTypes = new Set(['dead_stock', 'no_recent_sales', 'stock_risk', 'missing_cost', 'competitor_lower_price', 'price_attack', 'low_margin_risk', 'overstock', 'slow_mover']);
  const filteredSignals = signals.filter(signal => actionableTypes.has(signal.type));
  const opportunityType = phase17AOpportunityType(filteredSignals);
  const marginPct = cost != null && cost > 0 && currentPrice > 0 ? ((currentPrice - cost) / currentPrice) * 100 : null;
  const estimatedImpact = phase17AEstimatedImpact({ opportunityType, availableQuantity, currentPrice, recentSales, marginPct });
  const signalTypes = filteredSignals.map(signal => signal.type);
  const reasoning = [
    `Signals: ${signalTypes.join(', ') || 'none'}.`,
    `Current price ${phase17ARoundMoney(currentPrice)}, cost ${cost == null ? 'unknown' : phase17ARoundMoney(cost)}, available quantity ${availableQuantity}, recent sales ${recentSales}.`,
    opportunityType === 'missing_cost' ? 'Cost data is missing, so margin-sensitive actions require cost review before any pricing decision.' : null,
    ['competitor_lower_price', 'price_attack'].includes(opportunityType) ? 'Competitor pressure exists; any price action requires human review and a later approval-gated phase.' : null,
    ['dead_stock', 'no_recent_sales', 'overstock', 'slow_mover'].includes(opportunityType) ? 'Inventory is not moving quickly based on cached sales/inventory context; review inventory or merchandising before action.' : null,
    opportunityType === 'stock_risk' ? 'Stock is low or unavailable; review inventory before any sales or pricing action.' : null,
  ].filter(Boolean).join(' ');
  return {
    sku: context?.sku || sourceRow.sku || sourceRow.item_id || '',
    item_id: context?.platforms?.ebay?.listing_id || String(sourceRow.item_id || ''),
    title: context?.platforms?.ebay?.title || sourceRow.title || '',
    listing_status: context?.platforms?.ebay?.status || sourceRow.status || '',
    opportunity_type: opportunityType,
    signals: filteredSignals,
    current_price: phase17ARoundMoney(currentPrice),
    cost: cost == null ? 0 : phase17ARoundMoney(cost),
    available_quantity: availableQuantity,
    recent_sales: recentSales,
    estimated_impact: estimatedImpact,
    recommended_next_action: phase17ANextAction(opportunityType),
    requires_ai: false,
    requires_marketplace_write: false,
    reasoning,
    _score: filteredSignals.reduce((sum, signal) => sum + phase17ASignalPriority(signal.type), 0)
      + (estimatedImpact === 'high' ? 40 : estimatedImpact === 'medium' ? 20 : 0)
      + Math.min(50, Math.max(0, availableQuantity))
      + Math.min(30, Math.max(0, currentPrice)),
  };
}

async function phase17ALoadSeedRows(limit) {
  const db = getClient();
  const { data, error } = await db
    .from('ebay_products')
    .select('*')
    .order('updated_at', { ascending: false })
    .limit(Math.max(10, Math.min(200, limit * 4)));
  if (error) throw error;
  return data || [];
}

async function buildProfitInventoryOpportunityPlan({ limit = 50 } = {}) {
  const safeLimit = Math.max(1, Math.min(100, intOrNull(limit) || 50));
  const seedRows = await phase17ALoadSeedRows(safeLimit);
  const sourceBySku = new Map();
  for (const row of seedRows) {
    const sku = String(row.sku || row.item_id || '').trim();
    if (sku && !sourceBySku.has(sku)) sourceBySku.set(sku, row);
  }
  const opportunities = [];
  for (const [sku, row] of sourceBySku.entries()) {
    try {
      const context = await buildSkuContext({ sku, readOnly: true, skipConnector: true });
      const opportunity = phase17AOpportunityFromContext(context, row);
      if (opportunity.signals.length > 0) opportunities.push(opportunity);
    } catch (e) {
      const fallbackContext = {
        sku,
        platforms: { ebay: { listing_id: String(row.item_id || ''), title: row.title || '', price: row.price_usd || row.price || 0 } },
        inventory: { total_available: phase17AToInteger(row.ebay_api_stock ?? row.stock, 0) },
        sales: { units_30d: 0, orders_30d: 0 },
        pricing: { current_price: phase17AToNumber(row.price_usd ?? row.price, 0), estimated_margin_pct: null, needs_cost_data: true },
        competitors: [],
        signals: [],
      };
      const opportunity = phase17AOpportunityFromContext(fallbackContext, row);
      opportunity.reasoning = `${opportunity.reasoning} Context fallback used because read-only SKU context build failed: ${e.message || String(e)}.`;
      opportunities.push(opportunity);
    }
  }
  const ranked = opportunities
    .sort((a, b) => b._score - a._score || String(a.sku).localeCompare(String(b.sku)))
    .slice(0, safeLimit)
    .map((opportunity, index) => {
      const { _score, ...publicOpportunity } = opportunity;
      return { rank: index + 1, ...publicOpportunity };
    });
  return {
    phase: '17A',
    mode: 'read_only',
    image_pipeline_expansion_paused: true,
    limit: safeLimit,
    opportunities: ranked,
    marketplace_write: false,
    db_write: false,
    ai_call: false,
    no_execution_requests_created: true,
    no_packets_created: true,
    no_ebay_call: true,
    no_get_item_call: true,
    no_revise_fixed_price_item_call: true,
    no_price_inventory_listing_changes: true,
    safety: {
      read_only: true,
      cached_internal_data_only: true,
      marketplace_write: false,
      db_write: false,
      ai_call: false,
      get_item_called: false,
      revise_fixed_price_item_called: false,
      upload_site_hosted_pictures_called: false,
      execution_request_created: false,
      packet_created: false,
      price_changes: false,
      inventory_changes: false,
      listing_changes: false,
    },
    source: 'phase_17a_profit_inventory_opportunity_plan_v1',
  };
}

function phase17BClassifyOpportunity(opportunity) {
  const sku = String(opportunity?.sku || '').trim();
  const title = String(opportunity?.title || '').trim();
  const itemId = String(opportunity?.item_id || '').trim();
  const status = String(opportunity?.listing_status || '').trim().toLowerCase();
  const type = String(opportunity?.opportunity_type || '').trim();
  const price = phase17AToNumber(opportunity?.current_price, 0) || 0;
  const cost = phase17AToNumber(opportunity?.cost, 0) || 0;
  const signalTypes = (opportunity?.signals || []).map(signal => signal.type);
  const reasons = [];

  if (/\b(test|sample|mock|demo)\b/i.test(`${sku} ${title}`) || /(test|sample|mock|demo)/i.test(`${sku} ${title}`)) {
    reasons.push('test_or_sandbox_record');
  }
  if (price >= 999 && /test|sample|mock|demo/i.test(`${sku} ${title}`)) {
    reasons.push('suspicious_test_price');
  }
  if (!itemId) reasons.push('missing_item_id');
  if (!title) reasons.push('missing_title');
  if (status && !['active', 'in_stock', 'available'].includes(status)) {
    reasons.push(`inactive_or_unknown_listing_status:${status}`);
  }
  if (!type || type === 'hold') reasons.push('missing_clear_opportunity_type');
  if (opportunity?.requires_marketplace_write === true) reasons.push('requires_marketplace_write');

  const costDependentTypes = new Set(['missing_cost', 'competitor_lower_price', 'price_attack', 'low_margin_risk']);
  const marginOrRiskDecisionDependsOnCost = costDependentTypes.has(type)
    || signalTypes.some(signalType => costDependentTypes.has(signalType));
  if (marginOrRiskDecisionDependsOnCost && cost <= 0) {
    reasons.push('missing_or_zero_cost_for_margin_or_risk_decision');
  }

  let classification = 'actionable';
  if (reasons.some(reason => reason.includes('test_or_sandbox') || reason.includes('suspicious_test_price'))) {
    classification = 'test_or_sandbox_blocked';
  } else if (reasons.some(reason => reason.includes('missing_or_zero_cost'))) {
    classification = 'missing_cost_blocked';
  } else if (reasons.some(reason => reason === 'missing_item_id' || reason === 'missing_title' || reason.startsWith('inactive_or_unknown_listing_status'))) {
    classification = 'missing_listing_evidence_blocked';
  } else if (reasons.some(reason => reason === 'missing_clear_opportunity_type')) {
    classification = 'data_quality_blocked';
  } else if (['competitor_lower_price', 'price_attack', 'low_margin_risk'].includes(type)) {
    classification = 'needs_human_review';
  }

  const canOperatorReviewSafely = classification === 'actionable' || classification === 'needs_human_review';
  return {
    classification,
    blocked: classification !== 'actionable',
    blocked_reasons: reasons,
    can_operator_review_safely: canOperatorReviewSafely,
    hygiene_notes: reasons.length > 0
      ? reasons.join('; ')
      : 'passed Phase 17B hygiene filters for read-only operator review',
  };
}

function phase17BSummarizeBlockedReasons(rows) {
  const summary = {};
  for (const row of rows) {
    for (const reason of row.blocked_reasons || []) {
      summary[reason] = (summary[reason] || 0) + 1;
    }
  }
  return summary;
}

function phase17BPublicOpportunity(opportunity, hygiene) {
  return {
    rank: opportunity.rank,
    sku: opportunity.sku,
    item_id: opportunity.item_id,
    title: opportunity.title,
    listing_status: opportunity.listing_status || '',
    opportunity_type: opportunity.opportunity_type,
    classification: hygiene.classification,
    blocked_reasons: hygiene.blocked_reasons,
    signals: opportunity.signals || [],
    current_price: opportunity.current_price,
    cost: opportunity.cost,
    available_quantity: opportunity.available_quantity,
    recent_sales: opportunity.recent_sales,
    estimated_impact: opportunity.estimated_impact,
    recommended_next_action: opportunity.recommended_next_action,
    requires_ai: false,
    requires_marketplace_write: false,
    can_operator_review_safely: hygiene.can_operator_review_safely,
    reasoning: `${opportunity.reasoning || ''} Hygiene: ${hygiene.hygiene_notes}.`.trim(),
  };
}

async function buildProfitInventoryOpportunityHygiene({ limit = 50, shortlistLimit = null } = {}) {
  const safeLimit = Math.max(1, Math.min(100, intOrNull(limit) || 50));
  const plan = await buildProfitInventoryOpportunityPlan({ limit: safeLimit });
  const actionable = [];
  const blocked = [];

  for (const opportunity of plan.opportunities || []) {
    const hygiene = phase17BClassifyOpportunity(opportunity);
    const publicOpportunity = phase17BPublicOpportunity(opportunity, hygiene);
    if (hygiene.classification === 'actionable') {
      actionable.push(publicOpportunity);
    } else {
      blocked.push(publicOpportunity);
    }
  }

  const effectiveShortlistLimit = shortlistLimit == null
    ? null
    : Math.max(1, Math.min(100, intOrNull(shortlistLimit) || 25));
  const actionableOpportunities = effectiveShortlistLimit == null
    ? actionable
    : actionable.slice(0, effectiveShortlistLimit).map((opportunity, index) => ({ ...opportunity, rank: index + 1 }));

  return {
    phase: '17B',
    mode: 'read_only',
    input_limit: safeLimit,
    actionable_count: actionableOpportunities.length,
    blocked_count: blocked.length,
    blocked_reasons_summary: phase17BSummarizeBlockedReasons(blocked),
    actionable_opportunities: actionableOpportunities,
    blocked_opportunities: blocked,
    marketplace_write: false,
    db_write: false,
    ai_call: false,
    no_execution_requests_created: true,
    no_packets_created: true,
    no_ebay_call: true,
    no_get_item_call: true,
    no_revise_fixed_price_item_call: true,
    no_price_inventory_listing_changes: true,
    safety: {
      read_only: true,
      cached_internal_data_only: true,
      marketplace_write: false,
      db_write: false,
      ai_call: false,
      get_item_called: false,
      revise_fixed_price_item_called: false,
      upload_site_hosted_pictures_called: false,
      execution_request_created: false,
      packet_created: false,
      price_changes: false,
      inventory_changes: false,
      listing_changes: false,
    },
    source: effectiveShortlistLimit == null
      ? 'phase_17b_profit_inventory_opportunity_hygiene_v1'
      : 'phase_17b_profit_inventory_actionable_shortlist_v1',
  };
}

async function buildProfitInventoryActionableShortlist({ limit = 25, inputLimit = 50 } = {}) {
  const safeLimit = Math.max(1, Math.min(100, intOrNull(limit) || 25));
  const safeInputLimit = Math.max(safeLimit, Math.min(100, intOrNull(inputLimit) || 50));
  const result = await buildProfitInventoryOpportunityHygiene({
    limit: safeInputLimit,
    shortlistLimit: safeLimit,
  });
  return {
    ...result,
    shortlist_limit: safeLimit,
    source: 'phase_17b_profit_inventory_actionable_shortlist_v1',
  };
}

function phase17CCostValue(row = {}) {
  const keys = ['cost_usd', 'cost', 'unit_cost', 'purchase_cost', 'supplier_cost', 'item_cost', 'landed_cost', 'average_cost', 'avg_cost'];
  for (const key of keys) {
    if (Object.prototype.hasOwnProperty.call(row, key)) {
      const value = phase17AToNumber(row[key], null);
      if (value != null) return { key, value };
    }
  }
  const raw = row.raw || row.raw_data || row.metadata || {};
  if (raw && typeof raw === 'object') {
    for (const key of keys) {
      if (Object.prototype.hasOwnProperty.call(raw, key)) {
        const value = phase17AToNumber(raw[key], null);
        if (value != null) return { key: `raw.${key}`, value };
      }
    }
  }
  return { key: null, value: null };
}

function phase17CIsTestOrSandbox(row = {}) {
  return /(test|sample|mock|demo)/i.test(`${row.sku || ''} ${row.title || ''}`);
}

async function phase17CLoadCostRows(limit) {
  const safeLimit = Math.max(1, Math.min(1000, intOrNull(limit) || 500));
  const db = getClient();
  const { data, error } = await db
    .from('ebay_products')
    .select('*')
    .order('updated_at', { ascending: false })
    .limit(safeLimit);
  if (error) throw error;
  return data || [];
}

function phase17CRowSummary(row = {}) {
  const cost = phase17CCostValue(row);
  return {
    sku: String(row.sku || row.item_id || '').trim(),
    item_id: String(row.item_id || '').trim(),
    title: row.title || '',
    listing_status: row.status || '',
    current_price: phase17ARoundMoney(row.price_usd ?? row.price ?? 0),
    cost: cost.value == null ? 0 : phase17ARoundMoney(cost.value),
    cost_source_field: cost.key,
    is_test_or_sandbox: phase17CIsTestOrSandbox(row),
  };
}

function phase17CClassification(row = {}) {
  const text = JSON.stringify(row).toLowerCase();
  const summary = phase17CRowSummary(row);
  if (summary.is_test_or_sandbox) return 'should_exclude_test_or_sandbox';
  if (/purchase|po_|purchase_order|last_purchase|buy_cost/.test(text)) return 'can_infer_from_purchase_data';
  if (/supplier|vendor|wholesale|source_url|sourcing/.test(text)) return 'can_infer_from_supplier_data';
  if (/import|csv|upload|batch|sheet|spreadsheet/.test(text)) return 'can_infer_from_recent_import';
  if (summary.sku && summary.item_id && summary.title && summary.current_price > 0) return 'needs_manual_cost_input';
  return 'insufficient_data';
}

function phase17CSafety() {
  return {
    read_only: true,
    cached_internal_data_only: true,
    marketplace_write: false,
    db_write: false,
    ai_call: false,
    get_item_called: false,
    revise_fixed_price_item_called: false,
    upload_site_hosted_pictures_called: false,
    execution_request_created: false,
    packet_created: false,
    price_changes: false,
    inventory_changes: false,
    listing_changes: false,
  };
}

async function buildProfitInventoryCostCoverageAudit({ limit = 500, enrichmentLimit = 20 } = {}) {
  const safeLimit = Math.max(1, Math.min(1000, intOrNull(limit) || 500));
  const rows = await phase17CLoadCostRows(safeLimit);
  const scanned = rows.length;
  const withCostRows = [];
  const missingCostRows = [];
  const zeroCostRows = [];

  for (const row of rows) {
    const cost = phase17CCostValue(row);
    if (cost.value == null) {
      missingCostRows.push(row);
    } else if (cost.value > 0) {
      withCostRows.push(row);
    } else {
      zeroCostRows.push(row);
    }
  }

  const hygiene = await buildProfitInventoryOpportunityHygiene({ limit: Math.min(100, safeLimit) });
  const missingCostBlocked = (hygiene.blocked_opportunities || [])
    .filter(row => (row.blocked_reasons || []).includes('missing_or_zero_cost_for_margin_or_risk_decision'));
  const affectedOpportunityTypes = missingCostBlocked.reduce((acc, row) => {
    const type = row.opportunity_type || 'unknown';
    acc[type] = (acc[type] || 0) + 1;
    return acc;
  }, {});
  const candidateLimit = Math.max(1, Math.min(500, intOrNull(enrichmentLimit) || 20));
  const enrichmentSourceRows = [...zeroCostRows, ...missingCostRows].slice(0, candidateLimit);
  const enrichmentCandidates = enrichmentSourceRows.map((row, index) => ({
    rank: index + 1,
    ...phase17CRowSummary(row),
    enrichment_classification: phase17CClassification(row),
    recommended_next_action: phase17CClassification(row) === 'should_exclude_test_or_sandbox'
      ? 'exclude_from_profit_inventory_execution'
      : 'collect_cost_data',
    requires_ai: false,
    requires_marketplace_write: false,
  }));
  const coveragePct = scanned > 0 ? Math.round((withCostRows.length / scanned) * 10000) / 100 : 0;
  const recommendationBlockedCount = missingCostBlocked.length;
  const recommendationUnblockedCount = hygiene.actionable_count || 0;

  return {
    phase: '17C',
    mode: 'read_only',
    cost_coverage: {
      scanned,
      with_cost: withCostRows.length,
      missing_cost: missingCostRows.length,
      zero_cost: zeroCostRows.length,
      coverage_pct: coveragePct,
    },
    recommendation_unblocked_count: recommendationUnblockedCount,
    recommendation_blocked_count: recommendationBlockedCount,
    profit_inventory_recommendations_blocked: recommendationBlockedCount > 0 && recommendationUnblockedCount === 0,
    affected_opportunity_types: affectedOpportunityTypes,
    top_skus_blocked_by_missing_cost: missingCostBlocked.slice(0, 25).map(row => ({
      rank: row.rank,
      sku: row.sku,
      item_id: row.item_id,
      title: row.title,
      opportunity_type: row.opportunity_type,
      current_price: row.current_price,
      cost: row.cost,
      blocked_reasons: row.blocked_reasons,
    })),
    enrichment_candidates: enrichmentCandidates,
    next_step: recommendationBlockedCount > 0 ? 'cost_enrichment_required' : 'cost_coverage_sufficient_for_review',
    marketplace_write: false,
    db_write: false,
    ai_call: false,
    no_execution_requests_created: true,
    no_packets_created: true,
    no_ebay_call: true,
    no_get_item_call: true,
    no_revise_fixed_price_item_call: true,
    no_price_inventory_listing_changes: true,
    safety: phase17CSafety(),
    source: 'phase_17c_profit_inventory_cost_coverage_audit_v1',
  };
}

async function buildProfitInventoryCostEnrichmentPlan({ limit = 100, scanLimit = 500 } = {}) {
  const safeLimit = Math.max(1, Math.min(500, intOrNull(limit) || 100));
  const audit = await buildProfitInventoryCostCoverageAudit({
    limit: Math.max(safeLimit, Math.min(1000, intOrNull(scanLimit) || 500)),
    enrichmentLimit: safeLimit,
  });
  const classificationSummary = (audit.enrichment_candidates || []).reduce((acc, row) => {
    const key = row.enrichment_classification || 'insufficient_data';
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  return {
    ...audit,
    enrichment_limit: safeLimit,
    enrichment_classification_summary: classificationSummary,
    source: 'phase_17c_profit_inventory_cost_enrichment_plan_v1',
  };
}

