async function buildEbayImageUploadPayloadRoundtrip({ itemId } = {}) {
  const targetItemId = trimOrNull(itemId, 80);
  if (!targetItemId) throw new Error('item-id is required');
  const readiness = await buildEbayListingQualityImageSanitizedUploadReadiness({ itemId: targetItemId });
  const imagePath = readiness.sanitized_path;
  const expectedSha = readiness.sanitized_sha256;
  const blockers = [];
  if (targetItemId !== '206288370789') blockers.push('phase_14al_item_id_not_seed_item');
  if (!imagePath || !fs.existsSync(imagePath)) blockers.push('sanitized_image_missing');
  let payload = null;
  let originalBuffer = null;
  let decodedBuffer = null;
  let decodedSha = null;
  let extractedPictureData = null;
  let originalMagic = null;
  let decodedMagic = null;
  if (!blockers.length) {
    payload = EbayAPI.buildUploadSiteHostedPicturesPayload({
      imagePath,
      pictureName: `hermes-${targetItemId}-sanitized-replacement-image`,
      pictureSet: 'Supersize',
    });
    originalBuffer = fs.readFileSync(imagePath);
    extractedPictureData = (payload.requestXml.match(/<PictureData>([\s\S]*?)<\/PictureData>/i) || [])[1] || '';
    decodedBuffer = Buffer.from(extractedPictureData, 'base64');
    decodedSha = `sha256:${crypto.createHash('sha256').update(decodedBuffer).digest('hex')}`;
    originalMagic = originalBuffer.subarray(0, 12).toString('hex');
    decodedMagic = decodedBuffer.subarray(0, 12).toString('hex');
  }
  const pass = blockers.length === 0
    && decodedSha === expectedSha
    && Buffer.compare(originalBuffer, decodedBuffer) === 0
    && originalMagic === decodedMagic
    && /^ffd8ff/i.test(decodedMagic || '');
  return {
    read_only: true,
    phase: '14AL',
    item_id: targetItemId,
    image_path: imagePath || null,
    expected_sanitized_sha256: expectedSha || null,
    built_exact_intended_payload_locally: blockers.length === 0,
    upload_site_hosted_pictures_called: false,
    actual_ebay_call: false,
    actual_network_call: false,
    payload_transport: payload?.pictureDataTransport || 'PictureData',
    picture_url_transport_used: false,
    picture_data_base64_encoded: payload?.pictureDataBase64Encoded === true,
    binary_file_length: originalBuffer?.length || null,
    base64_length: payload?.base64Length || null,
    payload_content_length: payload?.payloadContentLength || null,
    original_magic_hex_prefix: originalMagic,
    decoded_magic_hex_prefix: decodedMagic,
    decoded_sha256: decodedSha,
    decoded_payload_bytes_match_original_file_bytes: pass,
    decoded_payload_sha256_matches_sanitized_image: decodedSha === expectedSha,
    jpeg_magic_bytes_survive_roundtrip: /^ffd8ff/i.test(decodedMagic || '') && originalMagic === decodedMagic,
    request_xml_shape_redacted: payload ? phase14ALRedactUploadXml(payload.requestXml) : null,
    base64_xml_safety: payload ? phase14ALBase64XmlSafety(payload.pictureData) : null,
    pass,
    blockers: [...new Set(blockers)],
    safety: {
      actual_ebay_call: false,
      actual_network_call: false,
      upload_site_hosted_pictures_called: false,
      revise_fixed_price_item_called: false,
      marketplace_write_performed: false,
      listing_changed: false,
      listing_revise_performed: false,
      image_uploaded: false,
      execution_request_created: false,
      packet_created: false,
      ai_calls: false,
    },
    source: 'phase_14al_payload_roundtrip_v1',
  };
}

async function buildEbayImageUploadPayloadAudit({ itemId } = {}) {
  const targetItemId = trimOrNull(itemId, 80);
  if (!targetItemId) throw new Error('item-id is required');
  const registry = phase14AAReadUploadResults();
  const allRows = (registry.uploads || []).filter(row => String(row.item_id || '') === String(targetItemId));
  const failures = allRows
    .filter(row => row.ebay_ack === 'Failure' || row.marketplace_image_upload_failed === true || row.upload_succeeded === false)
    .map(row => ({
      phase: row.phase || null,
      image_path: row.image_path || null,
      candidate_sha256: row.candidate_sha256 || null,
      ebay_ack: row.ebay_ack || null,
      picture_url: row.picture_url || null,
      upload_succeeded: row.upload_succeeded === true,
      sanitized_upload_attempt: row.sanitized_upload_attempt === true,
      post_token_refresh_upload_attempt: row.post_token_refresh_upload_attempt === true,
      corrected_upload_attempt: row.corrected_upload_attempt === true,
      error_codes: (row.errors || []).map(error => error?.code).filter(Boolean),
      errors: row.errors || [],
      timestamp: row.timestamp || row.recorded_at || null,
    }));
  const roundtrip = await buildEbayImageUploadPayloadRoundtrip({ itemId: targetItemId });
  const latest21916550Failures = failures.filter(row => row.error_codes.includes('21916550'));
  const original21916550 = latest21916550Failures.some(row => row.candidate_sha256 === 'sha256:16883e4cb7af5ebb12b6948285742faff7d83bdd501600f5fee01428620a1f47');
  const sanitized21916550 = latest21916550Failures.some(row => row.candidate_sha256 === 'sha256:98542bad69eed4a599263d2b4d779f9a2a9c8f4e27fc606040c62fd48b0f1f5f');
  const tokenRuledOut = failures.some(row => row.phase === '14AK' && row.error_codes.includes('21916550'))
    && !failures.some(row => row.phase === '14AK' && row.error_codes.includes('21916984'));
  const likelyPayloadIssue = roundtrip.pass
    ? 'No local PictureData encoding corruption found: payload uses base64 PictureData, XML escaping does not alter the base64 alphabet, decoded payload bytes exactly match the sanitized JPEG, and JPEG magic bytes survive. The repeated 21916550 is more likely eBay Picture Services rejecting the image content/encoding profile or the PictureData transport for this image than Hermes embedding raw or corrupted bytes.'
    : 'Local payload roundtrip failed; inspect PictureData extraction/base64 encoding before any future upload.';
  const recommendedFix = roundtrip.pass
    ? 'Keep the centralized safe base64 PictureData XML builder and do not retry live upload in this phase. Next remediation should create a materially different JPEG (fresh re-render/re-encode from pixels, different encoder/color profile/progressive settings) or test a disabled alternative strategy such as public HTTPS PictureURL/multipart EPS only after a new explicit approval.'
    : 'Fix PictureData base64 construction/extraction until roundtrip passes, then require a new explicit approval before any upload.';
  return {
    read_only: true,
    phase: '14AL',
    item_id: targetItemId,
    upload_site_hosted_pictures_called: false,
    revise_fixed_price_item_called: false,
    marketplace_write_performed: false,
    listing_changed: false,
    latest_image_upload_failures: failures.slice(-6),
    both_21916550_failures_present: original21916550 && sanitized21916550,
    original_image_21916550_failure_present: original21916550,
    sanitized_baseline_21916550_failure_present: sanitized21916550,
    token_auth_ruled_out_for_phase_14ak: tokenRuledOut,
    payload_transport_findings: {
      upload_site_hosted_pictures_used_picture_data: roundtrip.payload_transport === 'PictureData',
      upload_site_hosted_pictures_used_picture_url: false,
      picture_data_base64_encoded: roundtrip.picture_data_base64_encoded,
      xml_escaping_may_alter_base64: roundtrip.base64_xml_safety?.xml_escaping_may_alter_base64 === true,
      payload_content_length: roundtrip.payload_content_length,
      binary_file_length: roundtrip.binary_file_length,
      base64_length: roundtrip.base64_length,
      detected_jpeg_magic_bytes_before_encoding: roundtrip.original_magic_hex_prefix,
      decoded_payload_bytes_match_sanitized_file_bytes: roundtrip.decoded_payload_bytes_match_original_file_bytes,
      decoded_payload_sha256_matches_sanitized_image: roundtrip.decoded_payload_sha256_matches_sanitized_image,
      jpeg_magic_bytes_survive_roundtrip: roundtrip.jpeg_magic_bytes_survive_roundtrip,
    },
    current_request_xml_shape_secrets_omitted: roundtrip.request_xml_shape_redacted,
    likely_payload_issue: likelyPayloadIssue,
    recommended_fix: recommendedFix,
    disabled_future_strategy: {
      enabled: false,
      reason: 'No live retry or alternate upload transport is approved in Phase 14AL.',
      candidates: [
        'Re-render/re-encode a materially different baseline JPEG from pixels and re-audit locally.',
        'If eBay docs/support require it, test UploadSiteHostedPictures with PictureURL from a public HTTPS object instead of PictureData in a later explicitly approved phase.',
        'If confirmed necessary, prototype multipart/EPS transport in a disabled local-only branch before approval.',
      ],
    },
    local_payload_roundtrip: roundtrip,
    safety: {
      actual_ebay_call: false,
      actual_network_call: false,
      upload_site_hosted_pictures_called: false,
      revise_fixed_price_item_called: false,
      marketplace_write_performed: false,
      listing_changed: false,
      listing_revise_performed: false,
      image_uploaded: false,
      execution_request_created: false,
      packet_created: false,
      ai_calls: false,
    },
    source: 'phase_14al_payload_audit_v1',
  };
}

async function callEbayListingQualityImageUploadTransport({ itemId, dryRun = true, write = false, liveEnabled = false, operatorApprovalText = null } = {}) {
  const plan = await buildEbayListingQualityImageTransportPlan({ itemId });
  const candidate = {
    image_path: plan.candidate_path,
    sha256: plan.candidate_sha256,
    width: plan.candidate_width,
    height: plan.candidate_height,
    longest_side: plan.candidate_longest_side,
    format: 'jpeg',
    meets_ebay_500px_longest_side_policy: plan.candidate_policy_eligibility,
  };
  const intent = buildEbayImageTransportIntent({ itemId: plan.item_id, candidate });
  const isDryRun = dryRun !== false;
  const envUploadEnabled = String(process.env.HERMES_EBAY_IMAGE_UPLOAD_ENABLED || '').toLowerCase() === 'true';
  const exactSanitizedApprovalText = phase14AJExactSanitizedUploadApprovalText();
  const exactCompatibleApprovalText = phase14ANExactCompatibleUploadApprovalText();
  const exactTokenStableCompatibleApprovalText = phase14AQExactTokenStableCompatibleUploadApprovalText();
  const normalizedApprovalText = String(operatorApprovalText || '').replace(/\r\n/g, '\n').trim();
  const sanitizedUploadApprovalMatches = normalizedApprovalText === exactSanitizedApprovalText;
  const compatibleUploadApprovalMatches = normalizedApprovalText === exactCompatibleApprovalText;
  const tokenStableCompatibleUploadApprovalMatches = normalizedApprovalText === exactTokenStableCompatibleApprovalText;
  const sanitizedUploadReadiness = await buildEbayListingQualityImageSanitizedUploadReadiness({ itemId: plan.item_id });
  const compatibleUploadReadiness = await buildEbayListingQualityImageCompatibleUploadReadiness({ itemId: plan.item_id });
  const sanitizedCandidate = sanitizedUploadApprovalMatches
    ? {
        image_path: sanitizedUploadReadiness.sanitized_path,
        sha256: sanitizedUploadReadiness.sanitized_sha256,
        width: sanitizedUploadReadiness.sanitized_width,
        height: sanitizedUploadReadiness.sanitized_height,
        longest_side: sanitizedUploadReadiness.sanitized_longest_side,
        format: 'jpeg',
        meets_ebay_500px_longest_side_policy: sanitizedUploadReadiness.sanitized_policy_eligibility,
      }
    : null;
  const compatiblePreferred = compatibleUploadReadiness.preferred_candidate || null;
  const compatibleCandidate = (compatibleUploadApprovalMatches || tokenStableCompatibleUploadApprovalMatches)
    ? {
        image_path: compatibleUploadReadiness.expected_image_path,
        sha256: compatibleUploadReadiness.expected_candidate_sha256,
        width: compatiblePreferred?.width,
        height: compatiblePreferred?.height,
        longest_side: compatiblePreferred?.longest_side,
        format: compatiblePreferred?.format || 'jpeg',
        meets_ebay_500px_longest_side_policy: compatiblePreferred?.eligible_for_ebay_picture_policy === true,
      }
    : null;
  const uploadCandidatePath = compatibleCandidate?.image_path || sanitizedCandidate?.image_path || plan.candidate_path;
  const uploadCandidateSha256 = compatibleCandidate?.sha256 || sanitizedCandidate?.sha256 || plan.candidate_sha256;
  const uploadCandidateWidth = compatibleCandidate?.width || sanitizedCandidate?.width || plan.candidate_width;
  const uploadCandidateHeight = compatibleCandidate?.height || sanitizedCandidate?.height || plan.candidate_height;
  const uploadCandidateLongestSide = compatibleCandidate?.longest_side || sanitizedCandidate?.longest_side || plan.candidate_longest_side;
  const duplicateGuard = phase14AAUploadDuplicateGuard({ itemId: plan.item_id, candidateSha256: uploadCandidateSha256 });
  const exactCorrectedReapprovalText = [
    'Corrected eBay image upload transport approval after local pre-eBay exception.',
    'item_id=206288370789 only.',
    'image_path=/Users/parksungmin/Downloads/torune.jpeg only.',
    'candidate_sha256=sha256:16883e4cb7af5ebb12b6948285742faff7d83bdd501600f5fee01428620a1f47 exact match only.',
    'Allowed operation: UploadSiteHostedPictures only.',
    'Forbidden operation: ReviseFixedPriceItem.',
    'Forbidden changes: title, item_specifics, description, price, inventory, quantity, category, shipping, payment, returns.',
    'One corrected upload attempt only.',
    'Record returned PictureURL only.',
    'No listing revise in the upload phase.',
  ].join('\n');
  const exactPostTokenRefreshApprovalText = [
    'Post-token-refresh eBay image upload transport approval.',
    'item_id=206288370789 only.',
    'image_path=/Users/parksungmin/Downloads/torune.jpeg only.',
    'candidate_sha256=sha256:16883e4cb7af5ebb12b6948285742faff7d83bdd501600f5fee01428620a1f47 exact match only.',
    'Allowed operation: UploadSiteHostedPictures only.',
    'Forbidden operation: ReviseFixedPriceItem.',
    'Forbidden changes: title, item_specifics, description, price, inventory, quantity, category, shipping, payment, returns.',
    'One post-token-refresh upload attempt only.',
    'Record returned PictureURL only.',
    'No listing revise in the upload phase.',
  ].join('\n');
  const correctedReapprovalMatches = normalizedApprovalText === exactCorrectedReapprovalText;
  const postTokenRefreshApprovalMatches = normalizedApprovalText === exactPostTokenRefreshApprovalText;
  const postTokenRefreshReadiness = await buildEbayListingQualityImageUploadPostTokenRefreshReadiness({ itemId: plan.item_id });
  const previousPostTokenRefreshUploadAttemptExists = phase14AAUploadRowsFor({
    itemId: plan.item_id,
    candidateSha256: plan.candidate_sha256,
  }).some(row => row.post_token_refresh_upload_attempt === true || row.phase === '14AH');
  const previousSanitizedUploadAttemptExists = phase14AAUploadRowsFor({
    itemId: plan.item_id,
    candidateSha256: sanitizedUploadReadiness.sanitized_sha256,
  }).some(row => row.sanitized_upload_attempt === true || row.phase === '14AK');
  const previousCompatibleVariantUploadAttemptExists = phase14AAUploadRowsFor({
    itemId: plan.item_id,
    candidateSha256: compatibleUploadReadiness.expected_candidate_sha256,
  }).some(row => row.compatible_variant_upload_attempt === true || row.phase === '14AO');
  const latestUpload = duplicateGuard.latest_upload || null;
  const latestErrorText = Array.isArray(latestUpload?.errors)
    ? latestUpload.errors.map(error => error?.message || error?.long_message || error?.short_message || '').filter(Boolean).join('; ')
    : '';
  const previousAttemptWasLocalPreEbayException = latestUpload?.ebay_ack === 'Exception'
    && latestUpload?.raw_response == null
    && latestUpload?.picture_url == null
    && /EbayAPI is not defined/i.test(latestErrorText);
  const correctedUploadReapprovalActive = correctedReapprovalMatches
    && previousAttemptWasLocalPreEbayException
    && duplicateGuard.previous_corrected_upload_attempt_exists !== true;
  const postTokenRefreshUploadApprovalActive = postTokenRefreshApprovalMatches
    && postTokenRefreshReadiness.ready_for_post_token_refresh_upload_reapproval === true
    && previousPostTokenRefreshUploadAttemptExists !== true;
  const sanitizedUploadApprovalActive = sanitizedUploadApprovalMatches
    && sanitizedUploadReadiness.ready_for_sanitized_upload_reapproval === true
    && previousSanitizedUploadAttemptExists !== true;
  const compatibleVariantUploadApprovalActive = compatibleUploadApprovalMatches
    && compatibleUploadReadiness.ready_for_compatible_variant_upload_reapproval === true
    && previousCompatibleVariantUploadAttemptExists !== true;
  const tokenStableCompatibleUploadReadiness = tokenStableCompatibleUploadApprovalMatches
    ? await buildEbayCompatibleImageUploadTokenStabilityReadiness({ itemId: plan.item_id })
    : null;
  const tokenStableCompatibleUploadApprovalActive = tokenStableCompatibleUploadApprovalMatches
    && tokenStableCompatibleUploadReadiness?.ready_for_token_stable_upload_reapproval === true;
  const activeUploadPhase = tokenStableCompatibleUploadApprovalActive ? '14AR' : (compatibleVariantUploadApprovalActive ? '14AO' : (sanitizedUploadApprovalActive ? '14AK' : (postTokenRefreshUploadApprovalActive ? '14AH' : (correctedUploadReapprovalActive ? '14AC' : '14AA'))));
  const blockers = [...(plan.blockers || []), ...(intent.blockers || [])];
  const exact = {
    item_id_exact: plan.item_id === '206288370789',
    image_path_exact: (compatibleVariantUploadApprovalActive || tokenStableCompatibleUploadApprovalActive)
      ? uploadCandidatePath === '/Users/parksungmin/pmc-work-mvp/data/hermes-compatible-image-variants/206288370789-98542bad69eed4a5-srgb-white-800-q90-420-baseline.jpg'
      : (sanitizedUploadApprovalActive
        ? uploadCandidatePath === '/Users/parksungmin/pmc-work-mvp/data/hermes-sanitized-images/206288370789-16883e4cb7af5ebb-baseline.jpg'
        : plan.candidate_path === '/Users/parksungmin/Downloads/torune.jpeg'),
    candidate_sha256_exact: (compatibleVariantUploadApprovalActive || tokenStableCompatibleUploadApprovalActive)
      ? uploadCandidateSha256 === 'sha256:0c2a7b19e92af9e4762c879e6766864bac4c83c60e2f7ca6e8786abe234a6a6b'
      : (sanitizedUploadApprovalActive
        ? uploadCandidateSha256 === 'sha256:98542bad69eed4a599263d2b4d779f9a2a9c8f4e27fc606040c62fd48b0f1f5f'
        : plan.candidate_sha256 === 'sha256:16883e4cb7af5ebb12b6948285742faff7d83bdd501600f5fee01428620a1f47'),
    candidate_dimensions_exact: (compatibleVariantUploadApprovalActive || tokenStableCompatibleUploadApprovalActive)
      ? uploadCandidateWidth === 800 && uploadCandidateHeight === 800 && uploadCandidateLongestSide === 800
      : uploadCandidateWidth === 512 && uploadCandidateHeight === 512 && uploadCandidateLongestSide === 512,
    operation_exact_upload_site_hosted_pictures: intent.api_operation === 'UploadSiteHostedPictures',
    revise_fixed_price_item_disabled: true,
    no_listing_mutation_fields: true,
    request_id_5_not_reused: plan.failed_source_request_id === 5 && plan.failed_source_request_must_not_be_reused === true,
  };
  for (const [key, ok] of Object.entries(exact)) {
    if (ok !== true) blockers.push(key);
  }
  if (!isDryRun) {
    if (write !== true) blockers.push('explicit_cli_write_required');
    if (liveEnabled !== true || !envUploadEnabled) blockers.push('hermes_ebay_image_upload_env_disabled');
  }
  if (duplicateGuard.previous_successful_upload_exists) blockers.push('duplicate_successful_image_upload_for_item_candidate');
  if (previousCompatibleVariantUploadAttemptExists && !tokenStableCompatibleUploadApprovalActive) blockers.push('duplicate_compatible_variant_image_upload_attempt_for_item_candidate');
  if (!compatibleVariantUploadApprovalActive && !tokenStableCompatibleUploadApprovalActive && previousSanitizedUploadAttemptExists) blockers.push('duplicate_sanitized_image_upload_attempt_for_item_candidate');
  if (!compatibleVariantUploadApprovalActive && !tokenStableCompatibleUploadApprovalActive && !sanitizedUploadApprovalActive && previousPostTokenRefreshUploadAttemptExists) blockers.push('duplicate_post_token_refresh_image_upload_attempt_for_item_candidate');
  if (duplicateGuard.previous_corrected_upload_attempt_exists && !postTokenRefreshUploadApprovalActive && !sanitizedUploadApprovalActive && !compatibleVariantUploadApprovalActive && !tokenStableCompatibleUploadApprovalActive) blockers.push('duplicate_corrected_image_upload_attempt_for_item_candidate');
  if (duplicateGuard.previous_attempt_exists && !correctedUploadReapprovalActive && !postTokenRefreshUploadApprovalActive && !sanitizedUploadApprovalActive && !compatibleVariantUploadApprovalActive && !tokenStableCompatibleUploadApprovalActive) {
    if (postTokenRefreshApprovalMatches) blockers.push('post_token_refresh_upload_readiness_not_met');
    else if (sanitizedUploadApprovalMatches) blockers.push('sanitized_upload_readiness_not_met');
    else if (compatibleUploadApprovalMatches) blockers.push('compatible_variant_upload_readiness_not_met');
    else if (tokenStableCompatibleUploadApprovalMatches) blockers.push('token_stable_compatible_upload_readiness_not_met');
    else blockers.push(correctedReapprovalMatches ? 'duplicate_image_upload_attempt_for_item_candidate' : 'post_token_refresh_upload_exact_approval_required');
  }

  const base = {
    read_only: isDryRun,
    phase: activeUploadPhase,
    item_id: plan.item_id,
    image_path: uploadCandidatePath,
    candidate_sha256: uploadCandidateSha256,
    write_requested: write === true,
    live_enabled: liveEnabled === true,
    env_upload_enabled: envUploadEnabled,
    planned_future_api_operation: 'UploadSiteHostedPictures',
    expected_future_output: 'PictureURL',
    duplicate_guard: duplicateGuard,
    corrected_upload_reapproval_active: correctedUploadReapprovalActive,
    corrected_upload_reapproval_matches: correctedReapprovalMatches,
    post_token_refresh_upload_approval_active: postTokenRefreshUploadApprovalActive,
    post_token_refresh_upload_approval_matches: postTokenRefreshApprovalMatches,
    previous_post_token_refresh_upload_attempt_exists: previousPostTokenRefreshUploadAttemptExists,
    post_token_refresh_readiness: postTokenRefreshReadiness,
    sanitized_upload_approval_active: sanitizedUploadApprovalActive,
    sanitized_upload_approval_matches: sanitizedUploadApprovalMatches,
    previous_sanitized_upload_attempt_exists: previousSanitizedUploadAttemptExists,
    sanitized_upload_readiness: sanitizedUploadReadiness,
    compatible_variant_upload_approval_active: compatibleVariantUploadApprovalActive,
    compatible_variant_upload_approval_matches: compatibleUploadApprovalMatches,
    previous_compatible_variant_upload_attempt_exists: previousCompatibleVariantUploadAttemptExists,
    compatible_upload_readiness: compatibleUploadReadiness,
    token_stable_compatible_upload_approval_active: tokenStableCompatibleUploadApprovalActive,
    token_stable_compatible_upload_approval_matches: tokenStableCompatibleUploadApprovalMatches,
    token_stable_compatible_upload_readiness: tokenStableCompatibleUploadReadiness,
    previous_attempt_was_local_pre_ebay_exception: previousAttemptWasLocalPreEbayException,
    exact_gate_checks: exact,
    upload_attempt_count: isDryRun ? 0 : duplicateGuard.previous_attempt_count + 1,
    revise_fixed_price_item_called: false,
    listing_revise_performed: false,
    listing_changed: false,
    marketplace_write_performed: false,
    safety: {
      actual_ebay_call: false,
      actual_network_call: false,
      upload_site_hosted_pictures_called: false,
      revise_fixed_price_item_called: false,
      marketplace_write_performed: false,
      listing_changed: false,
      listing_revise_performed: false,
      image_uploaded: false,
      execution_request_created: false,
      packet_created: false,
      title_changes: false,
      item_specifics_changes: false,
      description_changes: false,
      price_changes: false,
      inventory_changes: false,
      quantity_changes: false,
      category_changes: false,
      shipping_changes: false,
      payment_changes: false,
      returns_changes: false,
      ai_calls: false,
    },
  };

  if (isDryRun || blockers.length) {
    return {
      ...base,
      blocked: blockers.length > 0,
      blockers: [...new Set(blockers)],
      no_execution_performed: true,
      upload_site_hosted_pictures_called: false,
      image_uploaded: false,
      actual_ebay_call: false,
      actual_network_call: false,
      source: 'phase_14aa_image_upload_transport_blocked_or_dry_run_v1',
    };
  }

  const attemptedAt = new Date().toISOString();
  let uploadResponse = null;
  let caughtError = null;
  let attemptedEbayCall = false;
  try {
    const ebay = new EbayAPI();
    attemptedEbayCall = true;
    uploadResponse = await ebay.uploadSiteHostedPicture({
      imagePath: uploadCandidatePath,
      pictureName: (compatibleVariantUploadApprovalActive || tokenStableCompatibleUploadApprovalActive)
        ? `hermes-${plan.item_id}-compatible-replacement-image`
        : (sanitizedUploadApprovalActive ? `hermes-${plan.item_id}-sanitized-replacement-image` : `hermes-${plan.item_id}-replacement-image`),
      pictureSet: 'Supersize',
    });
  } catch (e) {
    caughtError = e;
  }

  const succeeded = uploadResponse?.success === true;
  const resultRecord = {
    phase: activeUploadPhase,
    item_id: plan.item_id,
    image_path: uploadCandidatePath,
    candidate_sha256: uploadCandidateSha256,
    ebay_ack: uploadResponse?.ack || (caughtError ? 'Exception' : 'Unknown'),
    picture_url: uploadResponse?.picture_url || null,
    errors: uploadResponse?.errors || (caughtError ? [{ message: caughtError.message || String(caughtError) }] : []),
    warnings: uploadResponse?.warnings || [],
    timestamp: uploadResponse?.timestamp || attemptedAt,
    recorded_at: new Date().toISOString(),
    upload_attempt_count: duplicateGuard.previous_attempt_count + 1,
    corrected_upload_attempt: correctedUploadReapprovalActive,
    corrected_reapproval_text_matched: correctedReapprovalMatches,
    post_token_refresh_upload_attempt: postTokenRefreshUploadApprovalActive,
    post_token_refresh_approval_text_matched: postTokenRefreshApprovalMatches,
    sanitized_upload_attempt: sanitizedUploadApprovalActive,
    sanitized_upload_approval_text_matched: sanitizedUploadApprovalMatches,
    compatible_variant_upload_attempt: compatibleVariantUploadApprovalActive || tokenStableCompatibleUploadApprovalActive,
    compatible_variant_upload_approval_text_matched: compatibleUploadApprovalMatches || tokenStableCompatibleUploadApprovalMatches,
    token_stable_compatible_variant_upload_attempt: tokenStableCompatibleUploadApprovalActive,
    token_stable_compatible_variant_upload_approval_text_matched: tokenStableCompatibleUploadApprovalMatches,
    upload_attempted: true,
    upload_succeeded: succeeded,
    marketplace_image_upload_performed: succeeded,
    marketplace_image_upload_failed: !succeeded,
    listing_revise_performed: false,
    revise_fixed_price_item_called: false,
    raw_response: uploadResponse?.raw_response || null,
    source: tokenStableCompatibleUploadApprovalActive
      ? 'phase_14ar_token_stable_compatible_variant_upload_site_hosted_pictures_result'
      : (compatibleVariantUploadApprovalActive
        ? 'phase_14ao_compatible_variant_upload_site_hosted_pictures_result'
        : (sanitizedUploadApprovalActive
        ? 'phase_14ak_sanitized_upload_site_hosted_pictures_result'
        : (postTokenRefreshUploadApprovalActive
          ? 'phase_14ah_post_token_refresh_upload_site_hosted_pictures_result'
          : (correctedUploadReapprovalActive ? 'phase_14ac_corrected_upload_site_hosted_pictures_result' : 'phase_14aa_upload_site_hosted_pictures_result')))),
  };
  const registry = phase14AAReadUploadResults();
  const updatedRegistry = phase14AAWriteUploadResults({
    version: 1,
    uploads: [...(registry.uploads || []), resultRecord],
  });

  return {
    ...base,
    read_only: false,
    blocked: false,
    blockers: [],
    no_execution_performed: false,
    upload_site_hosted_pictures_called: attemptedEbayCall,
    actual_ebay_call: attemptedEbayCall,
    actual_network_call: attemptedEbayCall,
    image_uploaded: succeeded,
    marketplace_image_upload_performed: succeeded,
    marketplace_image_upload_failed: !succeeded,
    ebay_ack: resultRecord.ebay_ack,
    picture_url: resultRecord.picture_url,
    errors: resultRecord.errors,
    warnings: resultRecord.warnings,
    timestamp: resultRecord.timestamp,
    result_record: resultRecord,
    registry_path: PHASE14AA_IMAGE_UPLOAD_RESULT_PATH,
    registry_upload_count: updatedRegistry.uploads.length,
    safety: {
      ...base.safety,
      actual_ebay_call: attemptedEbayCall,
      actual_network_call: attemptedEbayCall,
      upload_site_hosted_pictures_called: attemptedEbayCall,
      image_uploaded: succeeded,
      marketplace_write_performed: false,
      listing_changed: false,
      listing_revise_performed: false,
      revise_fixed_price_item_called: false,
    },
    source: tokenStableCompatibleUploadApprovalActive
      ? (succeeded ? 'phase_14ar_token_stable_compatible_variant_image_upload_transport_success_v1' : 'phase_14ar_token_stable_compatible_variant_image_upload_transport_failure_v1')
      : (compatibleVariantUploadApprovalActive
        ? (succeeded ? 'phase_14ao_compatible_variant_image_upload_transport_success_v1' : 'phase_14ao_compatible_variant_image_upload_transport_failure_v1')
        : (sanitizedUploadApprovalActive
        ? (succeeded ? 'phase_14ak_sanitized_image_upload_transport_success_v1' : 'phase_14ak_sanitized_image_upload_transport_failure_v1')
        : (postTokenRefreshUploadApprovalActive
          ? (succeeded ? 'phase_14ah_post_token_refresh_image_upload_transport_success_v1' : 'phase_14ah_post_token_refresh_image_upload_transport_failure_v1')
          : (correctedUploadReapprovalActive
            ? (succeeded ? 'phase_14ac_corrected_image_upload_transport_success_v1' : 'phase_14ac_corrected_image_upload_transport_failure_v1')
            : (succeeded ? 'phase_14aa_image_upload_transport_success_v1' : 'phase_14aa_image_upload_transport_failure_v1'))))),
  };
}

